import 'package:flutter_bloc/flutter_bloc.dart'; import '../model/session_stats.dart'; class SessionStatsCubit extends Cubit<SessionStats> { SessionStatsCubit() : super(const SessionStats()); void update({int? bytesSent, int? bytesReceived, double? bitrate, int? reconnect}) { emit(SessionStats(duration: state.duration, bytesSent: bytesSent ?? state.bytesSent, bytesReceived: bytesReceived ?? state.bytesReceived, avgBitrateKbps: bitrate ?? state.avgBitrateKbps, reconnects: reconnect != null ? state.reconnects + 1 : state.reconnects)); } void tick() => emit(SessionStats(duration: state.duration + const Duration(seconds: 1), bytesSent: state.bytesSent, bytesReceived: state.bytesReceived, avgBitrateKbps: state.avgBitrateKbps, reconnects: state.reconnects)); }